var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"후아, 아슬아슬했네요.","JPN":"ふう、ギリギリでしたね。","ENG":"Whoa, that was close.","TWN":"呼啊，好險啊。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래. 수정을 건지지 못한 건 좀 아쉽지만.","JPN":"そうだな。水晶を持ってこれなかったのはちょっと惜しいが。","ENG":"Tell me about it. Too bad we couldn't recover the crystal.","TWN":"是啊，雖然沒拿到水晶有點可惜。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"저 잔해들을 다시 파헤치면서 찾기엔 시간이 없군. 포기하는 수밖에.","JPN":"あの残骸を探って見つけるには時間がないな。諦めるしかない。","ENG":"We don't have enough time to dig through the rubble. I guess we'll just have to do without it.","TWN":"沒時間從那些殘骸裡尋找了，只能放棄。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그보다 꼬맹이 너, 나오기 직전에 뭐 하고 있었던 거야.","JPN":"それよりガキ、出る直前に何してたんだ。","ENG":"By the way, kid. What were you doing in there before we ran?","TWN":"話說回來，小鬼，出來之前你在做什麼。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"넹? 저 계속 리타 언니 뒤에 있었는데요?","JPN":"え？　私はずっとリタお姉ちゃんの後ろにいましたよ？","ENG":"Huh? I was right behind you.","TWN":"嗯？我一直都在麗塔姐姐身後啊。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아니. 한창 싸우고 있을 때 갑자기 내 옆에서 사라졌어.","JPN":"いや、戦っている最中に急に私の傍から消えた。","ENG":"Yeah, right. I know you disappeared while I was fighting.","TWN":"不。在我打架的時候你突然消失了。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"네 말대로 얌전히 뒤에 있었으면 부를 일도 없었겠지.","JPN":"本当に大人しく後ろにいたなら呼ぶこともなかっただろ。","ENG":"I wouldn't have had to call for you if you were right behind me.","TWN":"如果按你說的有乖乖在我身後，那我就不會喊你了。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"정말이에요! 총알이 막 날아와서 정신 없긴 했지만 꼭 붙어 있었는걸요!","JPN":"本当ですよ！　銃弾が飛び交ってバタバタしていたけど、ちゃんとくっついていましたよ！","ENG":"I swear! Things got a bit hectic with all the bullets flying our way, but I stuck right behind you!","TWN":"真的！雖然子彈飛來飛去，但我真的一直都緊緊跟著你！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......그럼 방금 네 품에서 굴러 떨어진 그 수정은 뭔지 설명해 봐.","JPN":"……それじゃあ、今お前の服の中から転がり落ちたその水晶は何なのか説明してみろ。","ENG":"Then you'd better explain how you got your hands on that crystal you're trying to hide.","TWN":"……那剛才從你懷裡掉下來的水晶是怎麼回事，你解釋一下。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"어, 어라? 이럴 리가 없는데? 언제 챙겼지?","JPN":"あ、あれ？　これは何でしょう？　いつ持ってきたんだろう？","ENG":"H-huh? What's going on? I never took this!","TWN":"呃，哎呀？怎麼可能？我是什麼時候拿的？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"알았다! 수정에 발이 달렸나 봐요!","JPN":"わかった！　水晶に足が生えていたかもしれません！","ENG":"Alright, then! The crystal must have feet!","TWN":"我知道了！是水晶有長了腳！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"안 달렸어.","JPN":"そんなの付いてないぞ。","ENG":"It doesn't.","TWN":"並沒有長腳。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"하아...... 이미 가져와 버렸는데 이걸 혼낼 수도 없고......","JPN":"はあ……もう持って来たものを怒っても無駄だな……","ENG":"Ugh... I guess it's too late to scold you for bringing this...","TWN":"唉……拿都拿了，唸你有什麼用呢……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"헤헤, 어떻게 된 일인지는 몰라도 빈손으로 돌아가지 않아서 다행이네요.","JPN":"ヘヘッ、どういう訳かわからないけど、手ぶらで帰らずに済んでよかったです。","ENG":"Heh, I'm still not sure what happened, but at least we won't have to go back empty-handed.","TWN":"嘿嘿，雖然不知道是怎麼一回事，但總算不是空手而歸啊。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"맞다. 그래도 지진을 일으킨 건 심했어요, 언니.","JPN":"そうだ。とはいえ、地震を起こしたのはやりすぎですよ。","ENG":"Speaking of which. That earthquake was overkill, Rita.","TWN":"對了，引起地震確實有點過分了吧，姐姐。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"저희 둘 다 납작 오징어가 될 뻔했잖아요.","JPN":"私たち二人ともがれきの下敷きになりかけたんですから。","ENG":"You almost squashed us too.","TWN":"我們兩個差點就變成鐵板魷魚了呢。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"무슨 소리야. 내가 그런 무모한 짓을 왜 해.","JPN":"何言ってるんだ？　私がそんな無謀なことをするわけないだろ。","ENG":"What are you talking about? I wouldn't do anything so reckless.","TWN":"胡說什麼，我怎麼會做那種魯莽的事。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};